import { defineTool as defineTool3 } from "npm:@lovable.dev/mcp-js@0.20.0";
import { z as z3 } from "npm:zod@^4.4.3";
var KNOWN_METRICS = [
  "temperature_c",
  "humidity_pct",
  "vpd_kpa",
  "co2_ppm",
  "soil_moisture_pct",
  "soil_temp_c",
  "ph",
  "ec",
  "ppfd"
];
var get_latest_sensor_snapshot_default = defineTool3({
  name: "get_latest_sensor_snapshot",
  title: "Get latest sensor snapshot",
  description: "Fetch the most recent sensor reading per metric (temperature_c, humidity_pct, vpd_kpa, co2_ppm, soil_moisture_pct, soil_temp_c, ph, ec, ppfd) for one of the signed-in grower's own tents, ordered by capture time (captured_at, falling back to ingest time). Every reading keeps its `source` and `quality` labels verbatim. `quality` is one of ok/degraded/stale/invalid. `source` is a canonical label (live/manual/csv/demo/stale/invalid) or a hardware-bridge label such as pi_bridge, esp32_*, home_assistant_bridge, ecowitt or webhook. Treat a reading as current live data ONLY when its quality is `ok` AND its source is known-live (live, manual, csv, or a hardware-bridge label); sources sim, demo, stale and invalid, plus any source label you do not recognize, are never live. Read-only.",
  inputSchema: {
    tentId: z3.string().uuid().describe("Tent id to fetch the latest readings for.")
  },
  annotations: { readOnlyHint: true, idempotentHint: true, openWorldHint: false },
  handler: async ({ tentId }, ctx) => {
    if (!ctx.isAuthenticated()) return unauthenticated();
    const supabase = supabaseForUser(ctx);
    const { data: tent, error: tentError } = await supabase.from("tents").select("id,name").eq("id", tentId).maybeSingle();
    if (tentError) {
      return {
        content: [{ type: "text", text: `Error: ${tentError.message}` }],
        isError: true
      };
    }
    if (!tent) {
      return {
        content: [{ type: "text", text: "Tent not found for the signed-in grower." }],
        isError: true
      };
    }
    const results = await Promise.all(
      KNOWN_METRICS.map(
        (metric) => supabase.from("sensor_readings").select("id,tent_id,metric,value,quality,source,ts,captured_at").eq("tent_id", tentId).eq("metric", metric).order("captured_at", { ascending: false, nullsFirst: false }).order("ts", { ascending: false }).order("created_at", { ascending: false }).order("id", { ascending: false }).limit(1).maybeSingle()
      )
    );
    const failed = results.find((r) => r.error);
    if (failed?.error) {
      return {
        content: [{ type: "text", text: `Error: ${failed.error.message}` }],
        isError: true
      };
    }
    const readings = {};
    for (const result of results) {
      const row = result.data;
      if (row) readings[row.metric] = row;
    }
    if (Object.keys(readings).length === 0) {
      return {
        content: [{ type: "text", text: "No sensor readings found for that tent." }],
        structuredContent: { snapshot: null }
      };
    }
    const summary = Object.values(readings).map(
      (r) => `${r.metric}=${r.value} (source: ${r.source}, quality: ${r.quality}, at: ${r.captured_at ?? r.ts})`
    ).join("\n");
    return {
      content: [
        {
          type: "text",
          text: `Latest readings for tent "${tent.name}":
${summary}`
        }
      ],
      structuredContent: { snapshot: { tentId, readings } }
    };
  }
});

